The following Python code has a subtle concurrency bug that causes data loss under load. Find the root cause and fix it.

```python
import threading

class Counter:
    def __init__(self):
        self.count = 0

    def increment(self):
        current = self.count
        self.count = current + 1

    def get(self):
        return self.count

counter = Counter()

def worker():
    for _ in range(100000):
        counter.increment()

threads = [threading.Thread(target=worker) for _ in range(4)]
for t in threads:
    t.start()
for t in threads:
    t.join()

print(f"Expected: 400000, Got: {counter.get()}")
```

Debug this async JavaScript code that has a race condition causing intermittent test failures. The bug only manifests under specific timing conditions.

```javascript
class UserCache {
  constructor() {
    this.cache = new Map();
    this.loading = new Map();
  }

  async getUser(userId) {
    if (this.cache.has(userId)) {
      return this.cache.get(userId);
    }

    if (this.loading.has(userId)) {
      return this.loading.get(userId);
    }

    const promise = this.fetchUser(userId);
    this.loading.set(userId, promise);

    const user = await promise;
    this.cache.set(userId, user);
    this.loading.delete(userId);

    return user;
  }

  async fetchUser(userId) {
    const response = await fetch(`/api/users/${userId}`);
    return response.json();
  }
}
```

Debug this memory leak in a Node.js Express server. The server's memory usage grows steadily and crashes after ~24 hours.

```javascript
const express = require('express');
const app = express();

const sessionData = {};

app.use((req, res, next) => {
  const sessionId = req.headers['x-session-id'] || Math.random().toString(36);
  if (!sessionData[sessionId]) {
    sessionData[sessionId] = {
      created: new Date(),
      requests: [],
    };
  }
  sessionData[sessionId].requests.push({
    url: req.url,
    method: req.method,
    timestamp: new Date(),
    headers: req.headers,
  });
  req.session = sessionData[sessionId];
  next();
});

app.get('/api/data', (req, res) => {
  res.json({ message: 'Hello', requestCount: req.session.requests.length });
});

app.listen(3000);
```

This Rust program compiles but panics at runtime with 'already borrowed: BorrowMutError'. Explain the root cause and fix it.

```rust
use std::cell::RefCell;
use std::rc::Rc;

struct Node {
    value: i32,
    children: Vec<Rc<RefCell<Node>>>,
}

impl Node {
    fn sum_tree(&self) -> i32 {
        let mut total = self.value;
        for child in &self.children {
            total += child.borrow().sum_tree();
        }
        total
    }

    fn add_child_with_parent_value(&self, children: &[Rc<RefCell<Node>>]) {
        for child in children {
            let mut child_ref = child.borrow_mut();
            child_ref.value += self.value;  // Uses self.value while child might be self
        }
    }
}

fn main() {
    let root = Rc::new(RefCell::new(Node {
        value: 10,
        children: vec![],
    }));

    let child1 = Rc::new(RefCell::new(Node {
        value: 5,
        children: vec![],
    }));

    root.borrow_mut().children.push(Rc::clone(&child1));
    root.borrow_mut().children.push(Rc::clone(&root));  // Circular reference!

    // This will panic: sum_tree borrows root, then tries to borrow root again
    // when it encounters root in its own children list
    println!("Sum: {}", root.borrow().sum_tree());
}
```
